// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract CredentialRegistry {
    enum CredentialStatus {
        Valid,
        Revoked,
        Expired
    }

    struct CredentialRecord {
        string issuerDid;
        string holderDid;
        string ipfsHash;
        string signature;
        CredentialStatus status;
        uint256 issuedAt;
        uint256 revokedAt;
        bool exists;
    }

    mapping(string => CredentialRecord) private credentials;

    event CredentialRegistered(
        string credentialId,
        string issuerDid,
        string holderDid,
        string ipfsHash,
        string signature,
        uint256 issuedAt
    );
    event CredentialRevoked(string credentialId, uint256 revokedAt);

    function registerCredential(
        string calldata credentialId,
        string calldata issuerDid,
        string calldata holderDid,
        string calldata ipfsHash,
        string calldata signature
    ) external {
        require(bytes(credentialId).length > 0, "Credential ID required");
        require(!credentials[credentialId].exists, "Credential already registered");

        credentials[credentialId] = CredentialRecord({
            issuerDid: issuerDid,
            holderDid: holderDid,
            ipfsHash: ipfsHash,
            signature: signature,
            status: CredentialStatus.Valid,
            issuedAt: block.timestamp,
            revokedAt: 0,
            exists: true
        });

        emit CredentialRegistered(
            credentialId,
            issuerDid,
            holderDid,
            ipfsHash,
            signature,
            block.timestamp
        );
    }

    function revokeCredential(string calldata credentialId) external {
        CredentialRecord storage record = credentials[credentialId];
        require(record.exists, "Credential not found");
        require(record.status == CredentialStatus.Valid, "Credential not active");

        record.status = CredentialStatus.Revoked;
        record.revokedAt = block.timestamp;

        emit CredentialRevoked(credentialId, block.timestamp);
    }

    function getCredential(string calldata credentialId)
        external
        view
        returns (
            string memory issuerDid,
            string memory holderDid,
            string memory ipfsHash,
            string memory signature,
            CredentialStatus status,
            uint256 issuedAt,
            uint256 revokedAt
        )
    {
        CredentialRecord storage record = credentials[credentialId];
        require(record.exists, "Credential not found");

        return (
            record.issuerDid,
            record.holderDid,
            record.ipfsHash,
            record.signature,
            record.status,
            record.issuedAt,
            record.revokedAt
        );
    }
}

contracts/DIDRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract DIDRegistry {
    struct DIDRecord {
        address controller;
        string publicKey;
        uint256 createdAt;
        bool exists;
    }

    mapping(string => DIDRecord) private dids;

    event DIDRegistered(string did, address controller, string publicKey, uint256 createdAt);

    function registerDID(string calldata did, string calldata publicKey) external {
        require(bytes(did).length > 0, "DID required");
        require(!dids[did].exists, "DID already registered");

        dids[did] = DIDRecord({
            controller: msg.sender,
            publicKey: publicKey,
            createdAt: block.timestamp,
            exists: true
        });

        emit DIDRegistered(did, msg.sender, publicKey, block.timestamp);
    }

    function getDID(string calldata did)
        external
        view
        returns (address controller, string memory publicKey, uint256 createdAt)
    {
        DIDRecord storage record = dids[did];
        require(record.exists, "DID not found");

        return (record.controller, record.publicKey, record.createdAt);
    }
}

